-- İllerin hayvan sayısı verileri
-- Oluşturulma: 2026-02-04 23:34:10

DROP TABLE IF EXISTS `oner_i_llerin_hayvan_sayisi`;

CREATE TABLE `oner_i_llerin_hayvan_sayisi` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `il` VARCHAR(500),
  `sigir_varligi_bas` BIGINT,
  `manda_varligi_bas` BIGINT,
  `koyun_varligi_bas` BIGINT,
  `keci_varligi_bas` BIGINT,
  `arici_sayisi` BIGINT,
  `bal_uretimi_ton` DOUBLE,
  `aricilik_yapan_isletme_sayisi_adet` BIGINT,
  `yeni_kovan_sayisi_adet` BIGINT,
  `eski_kovan_sayisi_adet` BIGINT,
  `kovan_varligi_adet` BIGINT,
  `balmumu_uretimi_ton` DOUBLE,
  `bal_verimi_kg` DOUBLE,
  `bal_cesiti` VARCHAR(500),
  `peynir_cesiti` TEXT,
  `et_tavugu_sayisi` BIGINT,
  `yumurta_tavugu_sayisi` BIGINT,
  `toplam_hayvan_varligi` BIGINT,
  `tarih` DATETIME,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

